def p(g,R=range):
 for i in R(100):
  r=i//10;c=i%10
  if g[r][c]>4:
   b=r;d=c
   while b<9 and g[b+1][c]:b+=1
   while d<9 and g[r][d+1]:d+=1
   for j in R(r,b+1):
    for k in R(c,d+1):g[j][k]=[2,4,1][(j in(r,b))+(k in(c,d))]
 return g

